import React, { useState, useEffect } from "react";
import axios from "axios";
import Chart from "chart.js/auto"; // Chart.js for statistics
import { Bar } from "react-chartjs-2"; // For bar chart
import "./Admin.css";

const decodeUnicode = (str) => {
  return str.replace(/\\u([\dA-F]{4})/gi, (match, grp) => {
    return String.fromCharCode(parseInt(grp, 16));
  });
};

const Admin = () => {
  const [currentSection, setCurrentSection] = useState("dashboard");
  const [data, setData] = useState([]);
  const [formData, setFormData] = useState({});
  const [isEditing, setIsEditing] = useState(false);
  const [roles, setRoles] = useState(["Administrator", "Manager"]);
  const [stats, setStats] = useState({ clients: 0, tours: 0, bookings: 0 });

  useEffect(() => {
    if (currentSection !== "dashboard") fetchData(currentSection);
    if (currentSection === "dashboard") fetchStats();
  }, [currentSection]);

  const fetchData = async (section) => {
    try {
      const response = await axios.get(`/api/${section}`);
      const decodedData = response.data.map((item) =>
        Object.fromEntries(
          Object.entries(item).map(([key, value]) => [key, decodeUnicode(value.toString())])
        )
      );
      setData(decodedData);
    } catch (error) {
      console.error("Error fetching data:", error);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get("/api/statistics");
      setStats(response.data);
    } catch (error) {
      console.error("Error fetching statistics:", error);
    }
  };

  const handleSave = async () => {
    try {
      if (isEditing) {
        await axios.put(`/api/${currentSection}/${formData.id}`, formData);
      } else {
        await axios.post(`/api/${currentSection}`, formData);
      }
      fetchData(currentSection);
      setFormData({});
      setIsEditing(false);
    } catch (error) {
      console.error("Error saving data:", error);
    }
  };

  const handleDelete = async (id) => {
    try {
      await axios.delete(`/api/${currentSection}/${id}`);
      fetchData(currentSection);
    } catch (error) {
      console.error("Error deleting data:", error);
    }
  };

  const renderTable = () => {
    if (!data.length) return <p>No data available.</p>;

    return (
      <table className="admin-table">
        <thead>
          <tr>
            {Object.keys(data[0]).map((key) => (
              <th key={key}>{key}</th>
            ))}
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {data.map((item) => (
            <tr key={item.id}>
              {Object.values(item).map((value, index) => (
                <td key={index}>{value}</td>
              ))}
              <td>
                <button
                  className="btn-edit"
                  onClick={() => {
                    setFormData(item);
                    setIsEditing(true);
                  }}
                >
                  Edit
                </button>
                <button
                  className="btn-delete"
                  onClick={() => handleDelete(item.id)}
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  const renderForm = () => {
    return (
      <div className="form-container">
        {Object.keys(formData).map((key) => (
          <div className="form-group" key={key}>
            <label>{key}</label>
            <input
              type="text"
              value={formData[key] || ""}
              onChange={(e) =>
                setFormData({ ...formData, [key]: e.target.value })
              }
            />
          </div>
        ))}
        <button className="btn-save" onClick={handleSave}>
          {isEditing ? "Update" : "Save"}
        </button>
      </div>
    );
  };

  const renderStatistics = () => {
    const chartData = {
      labels: ["Clients", "Tours", "Bookings"],
      datasets: [
        {
          label: "Statistics Overview",
          data: [stats.clients, stats.tours, stats.bookings],
          backgroundColor: ["#8E44AD", "#3498DB", "#2ECC71"],
        },
      ],
    };

    return (
      <div className="statistics-section">
        <h3>Statistics</h3>
        <Bar data={chartData} />
      </div>
    );
  };

  return (
    <div className="admin-panel">
      <aside className="sidebar">
        <h2>Admin Panel</h2>
        <nav>
          <button onClick={() => setCurrentSection("dashboard")}>Dashboard</button>
          <button onClick={() => setCurrentSection("clients")}>Clients</button>
          <button onClick={() => setCurrentSection("countries")}>Countries</button>
          <button onClick={() => setCurrentSection("tours")}>Tours</button>
          <button onClick={() => setCurrentSection("bookings")}>Bookings</button>
          <button onClick={() => setCurrentSection("roles")}>Roles</button>
        </nav>
      </aside>

      <main className="main-content">
        {currentSection === "dashboard" ? (
          <>
            <div className="dashboard">
              <h3>Welcome to the Admin Dashboard</h3>
              <p>Use the navigation menu to manage data or view statistics below.</p>
            </div>
            {renderStatistics()}
          </>
        ) : (
          <div>
            <h3>{currentSection.charAt(0).toUpperCase() + currentSection.slice(1)}</h3>
            {renderTable()}
            {renderForm()}
          </div>
        )}
      </main>

      <footer className="footer">
        <p>&copy; {new Date().getFullYear()} Admin Panel. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default Admin;
